const trigger = $('Input: Customer Requirement').item.json;
const allMatches = $input.all().map(i => i.json);

const budget = Number(trigger.budget_aed) || 0;
const lowerBound = budget * 0.75;
const upperBound = budget * 1.25;

let scored = allMatches.map(p => {
  const price = Number(p.price_aed);
  const withinRange = price >= lowerBound && price <= upperBound;
  const priceDiff = Math.abs(price - budget);
  return { ...p, within_budget: withinRange, price_diff: priceDiff };
});

scored.sort((a, b) => {
  if (a.within_budget !== b.within_budget) return a.within_budget ? -1 : 1;
  return a.price_diff - b.price_diff;
});

const top3 = scored.slice(0, 3);

return {
  json: {
    session_id: trigger.session_id,
    area: trigger.area,
    property_type: trigger.property_type,
    budget_aed: budget,
    intent: trigger.intent,
    match_count: top3.length,
    matches: top3
  }
};
